#include <chrono>
#include <iostream>
#include <format>

int main() {
    using namespace std::chrono;

    // March 8, 2026: US clocks spring forward (2:00 AM -> 3:00 AM)
    const time_zone* ny = locate_zone("America/New_York");
    sys_days sd{year{2026}/March/8d};

    // 6:30 UTC = 1:30 EST (before transition)
    auto before = sd + hours{6} + minutes{30};
    zoned_time<minutes> zt_before{ny, before};
    std::cout << "before DST: " << std::format("{:%H:%M %Z}", zt_before) << "\n";

    // 8:00 UTC = 4:00 EDT (after transition)
    auto after = sd + hours{8};
    zoned_time<minutes> zt_after{ny, after};
    std::cout << "after DST:  " << std::format("{:%H:%M %Z}", zt_after) << "\n";

    // clock_cast: convert between clock types
    sys_seconds sys_tp{sd + hours{12}};
    utc_seconds utc_tp = clock_cast<utc_clock>(sys_tp);
    gps_seconds gps_tp = clock_cast<gps_clock>(sys_tp);

    // utc_clock accounts for leap seconds
    auto utc_sys_diff = utc_tp.time_since_epoch().count()
                      - sys_tp.time_since_epoch().count();
    std::cout << "UTC - system_clock diff: " << utc_sys_diff << " s (leap seconds)\n";
    std::cout << "GPS time_since_epoch: " << gps_tp.time_since_epoch().count() << " s\n";
}

